-- Table structure for `feature_importance`
-- ----------------------------
DROP TABLE IF EXISTS `feature_importance`;
CREATE TABLE `feature_importance` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `feature_name` varchar(100) NOT NULL COMMENT '特征名称',
  `importance` decimal(10,6) NOT NULL COMMENT '重要性值',
  `rank` int(11) NOT NULL COMMENT '排名',
  `model_type` varchar(50) NOT NULL DEFAULT 'random_forest' COMMENT '模型类型',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `idx_feature_name` (`feature_name`),
  KEY `idx_rank` (`rank`)
) ENGINE=InnoDB AUTO_INCREMENT=13 DEFAULT CHARSET=utf8mb4 COMMENT='特征重要性表';

