-- Table structure for `prediction_result`
-- ----------------------------
DROP TABLE IF EXISTS `prediction_result`;
CREATE TABLE `prediction_result` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `prediction_date` date NOT NULL COMMENT '预测日期',
  `predicted_sales` decimal(15,2) NOT NULL COMMENT '预测值（数量或金额）',
  `actual_sales` decimal(15,2) DEFAULT NULL COMMENT '实际值（数量或金额）',
  `error` decimal(15,2) DEFAULT NULL COMMENT '绝对误差',
  `relative_error` decimal(10,4) DEFAULT NULL COMMENT '相对误差百分比',
  `model_type` varchar(50) NOT NULL DEFAULT 'random_forest' COMMENT '模型类型',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `idx_prediction_date` (`prediction_date`)
) ENGINE=InnoDB AUTO_INCREMENT=1532 DEFAULT CHARSET=utf8mb4 COMMENT='预测结果表（预测销售数量或金额）';

